/* Medical Equipment Maintenance Dashboard — reads site/data.json (generated by build.py) */
"use strict";

const I18N = {
  ar: {
    app_title: "صيانة الأجهزة الطبية",
    tab_dashboard: "الرئيسية", tab_devices: "الأجهزة", tab_plan: "الإحلال", tab_parts: "قطع الغيار",
    kpi_total: "إجمالي الأجهزة", kpi_ff: "يعمل بكفاءة (FF)", kpi_pf: "يعمل جزئياً (PF)", kpi_nf: "لا يعمل (NF)",
    kpi_replace: "مطلوب إحلاله الآن", kpi_past_life: "تجاوز العمر الافتراضي",
    trc_dist: "توزيع التصنيف الفني TRC",
    status_dist: "الحالة الفنية",
    age_card: "العمر مقابل العمر الافتراضي",
    avg_age: "متوسط العمر", years: "سنة",
    expected_life: "العمر الافتراضي", of_fleet: "من الأجهزة",
    search_ph: "بحث بالكود أو المسلسل أو الماركة...",
    all: "الكل",
    brand: "الماركة", model: "الموديل", serial: "الرقم المسلسل", code: "الكود",
    year: "سنة الإنتاج", age: "العمر", status: "الحالة", trc: "TRC",
    faults: "الأعطال / الملاحظات", no_faults: "لا توجد أعطال مسجلة",
    score: "أولوية الإحلال", parts_for_device: "قطع الغيار المطلوبة",
    rec_replace_now: "إحلال فوري", rec_plan_replacement: "خطة إحلال", rec_monitor: "متابعة", rec_ok: "جيد",
    plan_intro: "ترتيب الأجهزة حسب أولوية الإحلال (التصنيف الفني TRC + الحالة + العمر)",
    trc_ref: "دليل التصنيف الفني TRC (مرجع)",
    parts_intro: "احتياجات قطع الغيار مجمعة من وصف الحالة الفنية لكل جهاز",
    pieces: "قطعة", device_count: "جهاز",
    no_results: "لا توجد نتائج",
    updated: "آخر تحديث",
    unknown: "غير محدد",
    reason_trc: "التصنيف الفني TRC {trc}", reason_status: "الحالة {status}",
    reason_age: "العمر {age} سنة من عمر افتراضي {life} سنة",
    status_FF: "يعمل بكامل الكفاءة", status_PF: "يعمل جزئياً", status_NF: "لا يعمل",
  },
  en: {
    app_title: "Medical Equipment Maintenance",
    tab_dashboard: "Dashboard", tab_devices: "Devices", tab_plan: "Replacement", tab_parts: "Spare Parts",
    kpi_total: "Total devices", kpi_ff: "Fully functional (FF)", kpi_pf: "Partially functional (PF)", kpi_nf: "Not functional (NF)",
    kpi_replace: "Replace now", kpi_past_life: "Past expected life",
    trc_dist: "TRC classification distribution",
    status_dist: "Technical status",
    age_card: "Age vs. expected life",
    avg_age: "Average age", years: "yrs",
    expected_life: "Expected life", of_fleet: "of fleet",
    search_ph: "Search by code, serial, or brand...",
    all: "All",
    brand: "Brand", model: "Model", serial: "Serial No.", code: "Code",
    year: "Production year", age: "Age", status: "Status", trc: "TRC",
    faults: "Faults / notes", no_faults: "No recorded faults",
    score: "Replacement priority", parts_for_device: "Parts needed",
    rec_replace_now: "Replace now", rec_plan_replacement: "Plan replacement", rec_monitor: "Monitor", rec_ok: "OK",
    plan_intro: "Devices ranked by replacement priority (TRC classification + status + age)",
    trc_ref: "TRC classification guide (reference)",
    parts_intro: "Spare-part needs aggregated from each device's fault description",
    pieces: "pcs", device_count: "devices",
    no_results: "No results",
    updated: "Last updated",
    unknown: "N/A",
    reason_trc: "TRC class {trc}", reason_status: "status {status}",
    reason_age: "{age} years old vs {life}-year expected life",
    status_FF: "Fully functional", status_PF: "Partially functional", status_NF: "Not functional",
  },
};

const REC_ORDER = ["replace_now", "plan_replacement", "monitor", "ok"];
const REC_COLOR = { replace_now: "#dc2626", plan_replacement: "#ea580c", monitor: "#d97706", ok: "#16a34a" };
const STATUS_COLOR = { FF: "#16a34a", PF: "#d97706", NF: "#dc2626" };
const TRC_COLOR = { 1: "#16a34a", 2: "#65a30d", 3: "#d97706", 4: "#ea580c", 5: "#dc2626" };

let DATA = null;
let lang = localStorage.getItem("lang") || "ar";
let currentView = "dashboard";
let currentCat = null;
let deviceFilter = "all"; // all | FF | PF | NF | replace_now...
let searchTerm = "";

const $ = (sel) => document.querySelector(sel);
const t = (key, vars) => {
  let s = (I18N[lang] && I18N[lang][key]) || key;
  if (vars) for (const [k, v] of Object.entries(vars)) s = s.replace(`{${k}}`, v);
  return s;
};
const esc = (s) => String(s ?? "").replace(/[&<>"']/g, (c) =>
  ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c]));

function catName(cat) { return lang === "ar" ? cat.name_ar : cat.name_en; }
function partName(key) {
  const p = DATA.part_names[key];
  return p ? (lang === "ar" ? p.ar : p.en) : key;
}
function cat() { return DATA.categories[currentCat]; }

/* ---------- shell ---------- */

function applyLang() {
  document.documentElement.lang = lang;
  document.documentElement.dir = lang === "ar" ? "rtl" : "ltr";
  $("#app-title").textContent = t("app_title");
  $("#lang-toggle").textContent = lang === "ar" ? "EN" : "ع";
  document.querySelectorAll("[data-i18n]").forEach((el) => (el.textContent = t(el.dataset.i18n)));
  const sel = $("#category-select");
  [...sel.options].forEach((o) => (o.textContent = catName(DATA.categories[o.value])));
  $("#subtitle").textContent = catName(cat());
}

function render() {
  applyLang();
  document.querySelectorAll(".tab").forEach((b) => b.classList.toggle("active", b.dataset.view === currentView));
  const view = $("#view");
  if (currentView === "dashboard") view.innerHTML = renderDashboard();
  else if (currentView === "devices") view.innerHTML = renderDevices();
  else if (currentView === "plan") view.innerHTML = renderPlan();
  else view.innerHTML = renderParts();
  bindViewEvents();
}

/* ---------- dashboard ---------- */

function renderDashboard() {
  const s = cat().stats;
  const life = cat().expected_life_years;
  const kpis = `
  <div class="kpi-grid">
    <div class="kpi"><div class="num">${s.total}</div><div class="lbl">${t("kpi_total")}</div></div>
    <div class="kpi green"><div class="num">${s.by_status.FF}</div><div class="lbl">${t("kpi_ff")}</div></div>
    <div class="kpi amber"><div class="num">${s.by_status.PF}</div><div class="lbl">${t("kpi_pf")}</div></div>
    <div class="kpi red"><div class="num">${s.by_status.NF}</div><div class="lbl">${t("kpi_nf")}</div></div>
  </div>`;

  const statusStack = `
  <div class="card"><h2>${t("status_dist")}</h2>
    <div class="stacked">${["FF", "PF", "NF"].map((k) =>
      `<div style="width:${(100 * s.by_status[k]) / s.total}%;background:${STATUS_COLOR[k]}"></div>`).join("")}
    </div>
    <div class="legend">${["FF", "PF", "NF"].map((k) =>
      `<span><span class="dot" style="background:${STATUS_COLOR[k]}"></span>${k} · ${s.by_status[k]}</span>`).join("")}
    </div>
  </div>`;

  const maxTrc = Math.max(...Object.values(s.by_trc), 1);
  const trcBars = `
  <div class="card"><h2>${t("trc_dist")}</h2>
    ${Object.entries(s.by_trc).map(([k, n]) => `
    <div class="bar-row">
      <span class="bar-label">TRC ${k}</span>
      <div class="bar-track"><div class="bar-fill" style="width:${(100 * n) / maxTrc}%;background:${TRC_COLOR[k] || "#64748b"}"></div></div>
      <span class="bar-num">${n}</span>
    </div>`).join("")}
  </div>`;

  const rec = s.by_recommendation;
  const recCards = `
  <div class="kpi-grid">
    <div class="kpi red"><div class="num">${rec.replace_now}</div><div class="lbl">${t("kpi_replace")}</div></div>
    <div class="kpi amber"><div class="num">${s.past_expected_life}</div><div class="lbl">${t("kpi_past_life")} (${s.past_expected_life_pct ?? 0}%)</div></div>
  </div>`;

  const note = lang === "ar" ? cat().life_note_ar : cat().life_note_en;
  const ageCard = `
  <div class="card"><h2>${t("age_card")}</h2>
    <div class="bar-row">
      <span class="bar-label">${t("avg_age")}</span>
      <div class="bar-track"><div class="bar-fill" style="width:${Math.min(100, (100 * s.avg_age) / (life * 1.5))}%;background:${s.avg_age >= life ? "#dc2626" : "#0e7490"}"></div></div>
      <span class="bar-num">${s.avg_age ?? "-"}</span>
    </div>
    <div class="life-note">${t("expected_life")}: ${life} ${t("years")}${note ? " — " + esc(note) : ""}</div>
  </div>`;

  const updated = `<div class="updated">${t("updated")}: ${new Date(DATA.generated_at).toLocaleString(lang === "ar" ? "ar-EG" : "en-GB")}</div>`;
  return kpis + recCards + statusStack + trcBars + ageCard + updated;
}

/* ---------- devices list ---------- */

function deviceMatches(d) {
  if (deviceFilter !== "all") {
    if (["FF", "PF", "NF"].includes(deviceFilter)) { if (d.status !== deviceFilter) return false; }
    else if (d.recommendation !== deviceFilter) return false;
  }
  if (!searchTerm) return true;
  const q = searchTerm.toLowerCase();
  return [d.code, d.serial, d.brand, d.model, ...(d.faults || [])].join(" ").toLowerCase().includes(q);
}

function deviceRow(d) {
  return `
  <button class="device-row" data-code="${esc(d.code)}">
    <span class="device-code">${esc(d.code)}</span>
    <span class="device-main">
      <span class="t1">${esc(d.brand)} ${esc(d.model)}</span><br>
      <span class="t2">${d.year || t("unknown")} · ${esc(d.serial) || t("unknown")}</span>
    </span>
    <span class="device-side">
      <span class="badge trc">TRC ${d.trc ?? "?"}</span>
      <span class="badge ${d.status}">${d.status}</span>
    </span>
  </button>`;
}

function renderDevices() {
  const chips = ["all", "FF", "PF", "NF", "replace_now"]
    .map((f) => {
      const label = f === "all" ? t("all") : f === "replace_now" ? t("rec_replace_now") : f;
      return `<button class="chip ${deviceFilter === f ? "active" : ""}" data-filter="${f}">${label}</button>`;
    }).join("");
  const list = cat().devices.filter(deviceMatches);
  const rows = list.length
    ? list.map(deviceRow).join("")
    : `<div class="empty">${t("no_results")}</div>`;
  return `
    <input class="searchbox" id="search" type="search" placeholder="${t("search_ph")}" value="${esc(searchTerm)}">
    <div class="filters">${chips}</div>
    ${rows}`;
}

/* ---------- replacement plan ---------- */

function renderPlan() {
  const groups = REC_ORDER.map((r) => {
    const list = cat().devices.filter((d) => d.recommendation === r);
    if (!list.length) return "";
    return `
    <div class="group-head" style="color:${REC_COLOR[r]}">
      <span>${t("rec_" + r)}</span><span class="count">(${list.length})</span>
    </div>
    ${list.map((d) => `
    <button class="device-row" data-code="${esc(d.code)}">
      <span class="score-pill" style="background:${REC_COLOR[r]}18;color:${REC_COLOR[r]}">${d.score}</span>
      <span class="device-main">
        <span class="t1">${esc(d.code)} — ${esc(d.brand)} ${esc(d.model)}</span><br>
        <span class="t2">TRC ${d.trc ?? "?"} · ${d.status} · ${d.age != null ? d.age + " " + t("years") : t("unknown")}</span>
      </span>
    </button>`).join("")}`;
  }).join("");

  const ref = `
  <div class="card"><details class="ref">
    <summary>${t("trc_ref")}</summary>
    ${DATA.trc_criteria.map((c) => `
    <div class="trc-block" style="border-color:${TRC_COLOR[c.trc]}">
      <div class="trc-title">TRC ${c.trc}</div>
      <div class="trc-verdict">${esc(lang === "ar" ? c.verdict_ar : c.verdict_en)}</div>
      <ul>${(lang === "ar" ? c.criteria_ar : c.criteria_en).map((x) => `<li>${esc(x)}</li>`).join("")}</ul>
    </div>`).join("")}
  </details></div>`;

  return `<div class="card" style="font-size:13px;color:var(--muted)">${t("plan_intro")}</div>${groups}${ref}`;
}

/* ---------- spare parts ---------- */

function renderParts() {
  const parts = cat().stats.parts_needed;
  const keys = Object.keys(parts);
  if (!keys.length) return `<div class="empty">${t("no_results")}</div>`;
  return `
  <div class="card" style="font-size:13px;color:var(--muted)">${t("parts_intro")}</div>
  ${keys.map((k) => `
  <div class="part-row">
    <div class="part-top">
      <span class="part-name">${esc(partName(k))}</span>
      <span class="part-qty">${parts[k].qty} ${t("pieces")}</span>
    </div>
    <div class="part-devices">${parts[k].devices.length} ${t("device_count")}:
      ${parts[k].devices.map((c) => `<span class="codechip">${esc(c)}</span>`).join("")}
    </div>
  </div>`).join("")}`;
}

/* ---------- device detail modal ---------- */

function openDevice(code) {
  const d = cat().devices.find((x) => x.code === code);
  if (!d) return;
  const life = d.expected_life;
  const ratio = d.age != null ? Math.min(d.age / life, 1.5) / 1.5 : 0;
  const lifeColor = d.age != null && d.age >= life ? "#dc2626" : "#0e7490";

  const reasons = [
    d.trc != null ? t("reason_trc", { trc: d.trc }) : "",
    t("reason_status", { status: `${d.status} (${t("status_" + d.status)})` }),
    d.age != null ? t("reason_age", { age: d.age, life }) : "",
  ].filter(Boolean).join(" · ");

  const partsHtml = d.parts_needed.length
    ? `<h2 style="margin-top:14px">${t("parts_for_device")}</h2>
       <ul class="fault-list">${d.parts_needed.map((p) =>
         `<li class="ok-line">${esc(partName(p.part))} × ${p.qty}</li>`).join("")}</ul>`
    : "";

  $("#modal-card").innerHTML = `
  <div class="modal-head">
    <span class="device-code">${esc(d.code)}</span>
    <div class="m-title">
      <div class="t1">${esc(d.brand)} ${esc(d.model)}</div>
      <div class="t2">${esc(d.serial) || t("unknown")}</div>
    </div>
    <button class="modal-close" id="modal-close">✕</button>
  </div>
  <div class="spec-grid">
    <div class="spec"><div class="k">${t("year")}</div><div class="v">${d.year || t("unknown")}</div></div>
    <div class="spec"><div class="k">${t("age")}</div><div class="v">${d.age != null ? d.age + " " + t("years") : t("unknown")}</div></div>
    <div class="spec"><div class="k">${t("trc")}</div><div class="v"><span class="badge trc">TRC ${d.trc ?? "?"}</span></div></div>
    <div class="spec"><div class="k">${t("status")}</div><div class="v"><span class="badge ${d.status}">${d.status} — ${t("status_" + d.status)}</span></div></div>
  </div>
  <h2>${t("age_card")}</h2>
  <div class="lifebar"><div style="width:${ratio * 100}%;background:${lifeColor}"></div></div>
  <div class="life-note">${t("expected_life")}: ${life} ${t("years")}</div>
  <h2 style="margin-top:14px">${t("faults")}</h2>
  ${d.faults.length
    ? `<ul class="fault-list">${d.faults.map((f) => `<li>${esc(f)}</li>`).join("")}</ul>`
    : `<div class="life-note">${t("no_faults")}</div>`}
  ${partsHtml}
  <div class="reason">
    <b>${t("score")}: ${d.score}/100 — <span style="color:${REC_COLOR[d.recommendation]}">${t("rec_" + d.recommendation)}</span></b><br>
    ${reasons}
  </div>`;
  $("#modal").hidden = false;
}

/* ---------- events ---------- */

function bindViewEvents() {
  document.querySelectorAll(".device-row").forEach((el) =>
    el.addEventListener("click", () => openDevice(el.dataset.code)));
  const search = $("#search");
  if (search) {
    search.addEventListener("input", () => {
      searchTerm = search.value;
      // re-render only the list part to keep the input focused
      const listStart = search.nextElementSibling.nextElementSibling;
      let node = listStart;
      while (node) { const next = node.nextElementSibling; node.remove(); node = next; }
      const list = cat().devices.filter(deviceMatches);
      $("#view").insertAdjacentHTML("beforeend",
        list.length ? list.map(deviceRow).join("") : `<div class="empty">${t("no_results")}</div>`);
      document.querySelectorAll(".device-row").forEach((el) =>
        el.addEventListener("click", () => openDevice(el.dataset.code)));
    });
  }
  document.querySelectorAll(".chip").forEach((c) =>
    c.addEventListener("click", () => { deviceFilter = c.dataset.filter; render(); }));
}

function boot() {
  $("#lang-toggle").addEventListener("click", () => {
    lang = lang === "ar" ? "en" : "ar";
    localStorage.setItem("lang", lang);
    render();
  });
  document.querySelectorAll(".tab").forEach((b) =>
    b.addEventListener("click", () => { currentView = b.dataset.view; searchTerm = ""; deviceFilter = "all"; render(); }));
  $("#modal").addEventListener("click", (e) => {
    if (e.target.id === "modal" || e.target.id === "modal-close") $("#modal").hidden = true;
  });

  fetch("data.json?v=" + Date.now())
    .then((r) => r.json())
    .then((data) => {
      DATA = data;
      const keys = Object.keys(data.categories);
      currentCat = keys[0];
      const sel = $("#category-select");
      sel.innerHTML = keys.map((k) => `<option value="${k}">${esc(catName(data.categories[k]))}</option>`).join("");
      sel.hidden = keys.length < 2;
      sel.addEventListener("change", () => { currentCat = sel.value; render(); });
      render();
    })
    .catch((err) => {
      $("#view").innerHTML = `<div class="empty">Failed to load data.json — ${esc(err.message)}</div>`;
    });
}

boot();
